var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"먼 옛날, 내 선조는 이 숲에 아름다운 저택을 세웠다.","JPN":"遠い昔、私の先祖はこの森に美しい邸宅を建てた。","ENG":"A long time ago, my ancestors built a beautiful mansion within this forest.","TWN":"很久以前，我的先祖在這片森林裡建了一棟漂亮的宅邸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어릴 적에는 그 이유를 몰랐지만, 지금은 알 수 있다.","JPN":"小さい頃はその理由がわからなかったが、今ならわかる。","ENG":"Back then, I could not figure out why... But now I know.","TWN":"小時候我不知道原因，現在我知道了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"바다 너머에서 어머니를 살릴 비법을 찾으려던 그는, 맞닥뜨리고 만 것이다.","JPN":"海の向こうでお母様を甦らす秘法を探していた彼は、出くわしてしまったのだ。","ENG":"For he had come across it, on his journey to find the cure to his mother’s illness.","TWN":"在大海彼岸尋找救活母親的方法的他，最找到了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"자신의 평생을, 아니, 누대에 걸쳐 봉인해야 할 금지된 지식을.","JPN":"一生、いや、代を渡って封印していかなければならない、禁止された知識に。","ENG":"He had found Forbidden Knowledge that would consume his whole life and bloodline to seal.","TWN":"找到需要耗盡他的一生，不，準確地說是，要耗盡幾代人封印的禁忌知識。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 돌아오시자마자 뭘 그렇게 뚫어져라 보고 계시는 거죠?","JPN":"レジーナ様、お戻りになったばかりなのに、何をそんなに見つめているのですか？","ENG":"Miss Regina, what are you staring at?","TWN":"蕾佳娜，一回來你就盯著看什麼呢？"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저를 연구해 주시기만을 기다리고 있답니다. 어서요.","JPN":"研究してくださるのを待っているのです。早く。","ENG":"We're waiting for you to start studying us. Please, proceed.","TWN":"我在等著你研究，快點吧。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"참으세요. 이번 사건으로 학회는 양지로 지나치게 많이 노출됐습니다.","JPN":"我慢しなさい。この度の事件で、学会は日の当たるところにその姿を露出しすぎました。","ENG":"Save your urges. The Society has been exposed to the public eye for too long during this incident.","TWN":"先忍一忍，這次事件會讓學會過度地暴露於陽光下。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"햇빛을 본 부분들은 모조리 도려내야 해요.","JPN":"日に当たった部分はすべて切り取らなければなりません。","ENG":"We must cut out all of the parts that have been exposed to light.","TWN":"見光的部分都要挖掉。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"제물로 삼을 계획이시군요.","JPN":"生贄にするおつもりですね。","ENG":"You plan to make them sacrifice.","TWN":"你是打算把他們當成祭物嗎。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇다면 우선 건축학부와 철학부겠죠. 합중국에서 가장 날뛴 학부들이랍니다.","JPN":"そういうことでしたら、まずは建築学部と哲学部でしょう。合衆国でもっとも暴れていた学部です。","ENG":"Then it should be the Architecture and Philosophy Departments. They were most active in the States.","TWN":"那麼首先應該是建築學院和哲學院吧。他們是在合眾國最猖狂的學院。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……그리고 고고학부까지.","JPN":"……そして考古学部も。","ENG":"...Followed by the Archeology Department.","TWN":"……還有考古學院。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"법학부장에게 서신을 보내야겠군요. 직접 처분하는 태도를 보여야 대화할 수 있을 겁니다.","JPN":"法学部長に手紙を送るべきですわね。直接処分する態度を見せないと、会話などできないはずです。","ENG":"I must go and write a letter to the Dean of Law. The only way to summon her will be to demonstrate that I will personally dispose of them.","TWN":"我得給法學院院長寫一封信。只有表現出親自處理的態度，才能和她對話。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"합중국 정부와 가교 역할을 할 인사가 필요해요.","JPN":"合衆国政府との間に立ってくれる人が必要です。","ENG":"I also need someone who can act as a diplomat with the States.","TWN":"我們需要在學會和合眾國政府之間發揮橋樑作用的人。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"사용한 뒤에는……","JPN":"使用した後は……","ENG":"After that...","TWN":"使用之後……"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"나는 두렵다.","JPN":"私は怖い。","ENG":"I am terrified.","TWN":"我很害怕。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가, 이대로 모든 것이 익숙해지는 날이.","JPN":"いつか、このまますべてに慣れてしまう日が来ることが。","ENG":"That the day will come when I will get used to all of this.","TWN":"害怕總有一天，會對所有的事情變得熟悉又麻木的那一天。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"파편들은 어떻게 되었죠?","JPN":"破片はどうなりましたか？","ENG":"What happened with the Fragments?","TWN":"碎片怎麼樣了？"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"합중국에 보낸 아이는 프리드웬이 망가뜨렸어요. 결국 일부만 회수할 수 있었답니다.","JPN":"合衆国に送った子は、プリドウェンに壊されてしまいました。結局、一部だけしか回収できませんでしたね。","ENG":"The one sent to the States was ruined by Prydwen. We were only able to retrieve parts of it.","TWN":"派去合眾國的孩子被普利多溫給毀了。最後只能回收一部分。"},"stage":{"bg":"ESPR2_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};